import warnings


def _warn_deprecated_exception(old_name, new_name):
    warnings.warn(
        f"overpass.{old_name} is deprecated and will be removed in overpass 1.0; "
        f"use overpass.{new_name} in 1.0 instead.",
        DeprecationWarning,
        stacklevel=3,
    )


class OverpassError(Exception):
    """An error occurred during an Overpass API request."""


class OverpassSyntaxError(OverpassError, ValueError):
    """The request contains a syntax error."""

    def __init__(self, request):
        self.request = request
        super().__init__(request)


class TimeoutError(OverpassError):
    """A request timeout occurred."""

    def __init__(self, timeout):
        _warn_deprecated_exception("TimeoutError", "OverpassTimeout")
        self.timeout = timeout
        super().__init__(f"Request timed out after {timeout} seconds.")


class MultipleRequestsError(OverpassError):
    """You are trying to run multiple requests at the same time."""

    def __init__(self):
        _warn_deprecated_exception("MultipleRequestsError", "OverpassRateLimited")
        super().__init__("Multiple requests are already running.")


class ServerLoadError(OverpassError):
    """The Overpass server is currently under load and declined the request.
    Try again later or retry with reduced timeout value."""

    def __init__(self, timeout):
        _warn_deprecated_exception("ServerLoadError", "OverpassServerBusy")
        self.timeout = timeout
        super().__init__(
            "The Overpass server is under load. "
            f"Try again later or retry with a timeout below {timeout} seconds."
        )


class UnknownOverpassError(OverpassError):
    """An unknown kind of error happened during the request."""

    def __init__(self, message):
        _warn_deprecated_exception("UnknownOverpassError", "OverpassError")
        self.message = message
        super().__init__(message)


class ServerRuntimeError(OverpassError):
    """The Overpass server returned a runtime error."""

    def __init__(self, message):
        _warn_deprecated_exception("ServerRuntimeError", "OverpassRuntimeError")
        self.message = message
        super().__init__(message)
